import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const TourForm = ({ tours, setTours, editingTour, setEditingTour }) => {
  const { user } = useAuth();

  // 按照截圖增加欄位：日期、備註、容納人數、折扣、狀態
  const [formData, setFormData] = useState({ 
    title: '', 
    location: '',
    startDate: '',
    endDate: '',
    description: '',
    importantNotes: '',
    capacity: '',
    price: '', 
    discount: '',
    status: 'Available'
  });

  useEffect(() => {
    if (editingTour) {
      setFormData({ ...editingTour });
    } else {
      setFormData({ 
        title: '', location: '', startDate: '', endDate: '', 
        description: '', importantNotes: '', capacity: '', 
        price: '', discount: '', status: 'Available' 
      });
    }
  }, [editingTour]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      if (editingTour) {
        const response = await axiosInstance.put(`/api/tours/${editingTour._id}`, formData, {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setTours(tours.map((t) => (t._id === response.data._id ? response.data : t)));
      } else {
        const response = await axiosInstance.post('/api/tours', formData, {
          headers: { Authorization: `Bearer ${user.token}` },
        });
        setTours([...tours, response.data]);
      }
      setEditingTour(null);
      alert('Success!');
    } catch (error) {
      alert('Error saving tour.');
    }
  };

  return (
    <div className="max-w-md mx-auto bg-white min-h-screen pb-10">
      {/* Header */}
      <div className="flex items-center p-4 border-b">
        <button onClick={() => setEditingTour(null)} className="text-xl">←</button>
        <h1 className="flex-1 text-center font-bold text-lg">Add Tour Package</h1>
        <span className="text-xl">🏠</span>
      </div>

      <form onSubmit={handleSubmit} className="p-4 space-y-6 text-sm">
        {/* Tour Title */}
        <div>
          <label className="block font-bold mb-1">Tour Title</label>
          <input
            type="text"
            placeholder="Enter tour title"
            value={formData.title}
            onChange={(e) => setFormData({ ...formData, title: e.target.value })}
            className="w-full p-3 border rounded-lg bg-gray-50 focus:bg-white"
          />
        </div>

        {/* Location */}
        <div>
          <label className="block font-bold mb-1">Location</label>
          <input
            type="text"
            placeholder="Enter tour location"
            value={formData.location}
            onChange={(e) => setFormData({ ...formData, location: e.target.value })}
            className="w-full p-3 border rounded-lg bg-gray-50 focus:bg-white"
          />
        </div>

        {/* Dates */}
        <div className="flex space-x-4">
          <div className="flex-1">
            <label className="block font-bold mb-1">Start Date</label>
            <input
              type="date"
              value={formData.startDate}
              onChange={(e) => setFormData({ ...formData, startDate: e.target.value })}
              className="w-full p-3 border rounded-lg bg-gray-50 text-gray-400"
            />
          </div>
          <div className="flex-1">
            <label className="block font-bold mb-1">End Date</label>
            <input
              type="date"
              value={formData.endDate}
              onChange={(e) => setFormData({ ...formData, endDate: e.target.value })}
              className="w-full p-3 border rounded-lg bg-gray-50 text-gray-400"
            />
          </div>
        </div>

        {/* Description */}
        <div>
          <label className="block font-bold mb-1">What is it about</label>
          <textarea
            placeholder="Enter description"
            rows="4"
            value={formData.description}
            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
            className="w-full p-3 border rounded-lg bg-gray-50"
          />
        </div>

        {/* Important Notes */}
        <div>
          <label className="block font-bold mb-1">Important Notes:</label>
          <textarea
            placeholder="Enter Important Notes of the tour"
            rows="3"
            value={formData.importantNotes}
            onChange={(e) => setFormData({ ...formData, importantNotes: e.target.value })}
            className="w-full p-3 border rounded-lg bg-gray-50"
          />
        </div>

        {/* Upload Picture (UI Only for now) */}
        <div>
          <label className="block font-bold mb-1">Upload cover picture</label>
          <div className="border-2 border-dashed border-gray-200 rounded-lg p-6 text-center text-gray-400">
            <span className="block text-2xl mb-2">☁️</span>
            <p className="font-bold text-gray-700">Click to upload</p>
            <p className="text-xs">SVG, PNG, JPG or GIF (max. 800x400px)</p>
          </div>
        </div>

        {/* Capacity */}
        <div>
          <label className="block font-bold mb-1">Capacity (/day)</label>
          <input
            type="number"
            placeholder="Enter the maximum daily capacity"
            value={formData.capacity}
            onChange={(e) => setFormData({ ...formData, capacity: e.target.value })}
            className="w-full p-3 border rounded-lg bg-gray-50"
          />
        </div>

        {/* Price & Discount */}
        <div className="flex space-x-4">
          <div className="flex-1">
            <label className="block font-bold mb-1">Price (in AUD)</label>
            <div className="relative">
              <span className="absolute left-3 top-3 text-gray-400">$</span>
              <input
                type="number"
                placeholder="Enter price"
                value={formData.price}
                onChange={(e) => setFormData({ ...formData, price: e.target.value })}
                className="w-full p-3 pl-8 border rounded-lg bg-gray-50"
              />
            </div>
          </div>
          <div className="flex-1">
            <label className="block font-bold mb-1">Discount</label>
            <input
              type="number"
              placeholder="Enter price"
              value={formData.discount}
              onChange={(e) => setFormData({ ...formData, discount: e.target.value })}
              className="w-full p-3 border rounded-lg bg-gray-50"
            />
          </div>
        </div>

        {/* Status Dropdown */}
        <div>
          <label className="block font-bold mb-1">Status</label>
          <select
            value={formData.status}
            onChange={(e) => setFormData({ ...formData, status: e.target.value })}
            className="w-full p-3 border rounded-lg bg-gray-50 appearance-none"
          >
            <option value="Available">Available</option>
            <option value="Unavailable">Unavailable</option>
          </select>
        </div>

        {/* Submit Button */}
        <button type="submit" className="w-full bg-emerald-500 text-white font-bold py-4 rounded-xl hover:bg-emerald-600 transition">
          Submit
        </button>
      </form>
    </div>
  );
};

export default TourForm;
